import React, { useState, useEffect } from 'react';

function Login({ onLogin }) {
  const [view, setView] = useState('landing');
  const [bgIndex, setBgIndex] = useState(0);

  // High-quality Farm/Agri images (No cycles!)
  const farmImages = [
    "https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?q=80&w=2000", // Tractor in field
    "https://images.unsplash.com/photo-1595855759920-86582396756a?q=80&w=2000", // Fresh Harvest
    "https://images.unsplash.com/photo-1500382017468-9049fed747ef?q=80&w=2000"  // Vast farmland
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setBgIndex((prev) => (prev < farmImages.length - 1 ? prev + 1 : 0));
    }, 5000);
    return () => clearInterval(interval);
  }, [farmImages.length]);

  return (
    <div className="container-fluid vh-100 d-flex align-items-center">
      {/* BACKGROUND SLIDER */}
      <div className="bg-slider">
        <img src={farmImages[bgIndex]} className="slider-img" alt="Farm Background" />
      </div>

      <div className="row w-100">
        {/* Left Side: Branding */}
        <div className="col-lg-7 d-none d-lg-flex flex-column justify-content-center px-5 text-white">
          <h1 className="display-3 fw-bold mb-3">Online Farm Portal</h1>
          <p className="fs-4 fw-light" style={{ borderLeft: '4px solid #75B946', paddingLeft: '20px' }}>
            Predictive AI for better crop yields. <br />
            Connecting farmers directly to global markets.
          </p>
        </div>

        {/* Right Side: Glass Login Card */}
        <div className="col-lg-4 col-md-8 mx-auto">
          <div className="glass-panel">
            <h2 className="mb-4 text-center">Get Started</h2>

            {view === 'landing' && (
              <div className="d-grid gap-3">
                <button className="btn-agri" onClick={() => setView('login')}>Login to Dashboard</button>
                <button className="btn btn-outline-light py-2" onClick={() => setView('signup-buyer')}>Join as Buyer</button>
                <button className="btn btn-outline-light py-2" style={{borderColor: '#AEB946'}} onClick={() => setView('signup-seller')}>Join as Seller</button>
              </div>
            )}

            {view === 'login' && (
              <form onSubmit={(e) => { e.preventDefault(); onLogin({role: 'buyer'}); }}>
                <input type="text" className="form-control form-control-agri mb-3" placeholder="Email / Mobile" />
                <input type="password" className="form-control form-control-agri mb-4" placeholder="Password" />
                <button className="btn-agri w-100 mb-3">Sign In</button>
                <p className="text-center small cursor-pointer" onClick={() => setView('landing')}>← Back</p>
              </form>
            )}

            {(view === 'signup-buyer' || view === 'signup-seller') && (
              <div style={{ maxHeight: '60vh', overflowY: 'auto', paddingRight: '5px' }}>
                <h4 className="text-center mb-4">{view === 'signup-seller' ? 'Seller Verification' : 'Buyer Profile'}</h4>
                <input type="text" className="form-control form-control-agri mb-2" placeholder="Full Name" />
                <input type="text" className="form-control form-control-agri mb-2" placeholder="Mobile" />
                <input type="text" className="form-control form-control-agri mb-2" placeholder="Location" />

                {view === 'signup-seller' && (
                  <>
                    <input type="text" className="form-control form-control-agri mb-2" placeholder="Aadhar / PAN Number" />
                    <label className="small mb-1">Income Proof (KYC)</label>
                    <input type="file" className="form-control form-control-agri mb-3" />
                  </>
                )}

                <input type="text" className="form-control form-control-agri mb-3" placeholder="Interests (Potatoes, Wheat, etc.)" />
                <button className="btn-agri w-100" onClick={() => onLogin({role: view.split('-')[1]})}>Complete Setup</button>
                <p className="text-center small mt-3 cursor-pointer" onClick={() => setView('landing')}>Cancel</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
